// الگوریتم تشخیص تغییر و آماده‌سازی متادیتا
const item = $input.first().json;
const source = item.source_system;
const recordId = item.record_id;
const data = item.payload_data;
const incomingTimestamp = new Date(item.timestamp).getTime();

// ایجاد Hash ساده برای تشخیص تغییر محتوایی
const dataString = JSON.stringify(data);
let hash = 0;
for (let i = 0; i < dataString.length; i++) {
  const char = dataString.charCodeAt(i);
  hash = ((hash << 5) - hash) + char;
  hash = hash & hash;
}

return [{
  json: {
    source_system: source,
    record_id: recordId,
    payload_data: data,
    incoming_timestamp: incomingTimestamp,
    data_hash: hash.toString(),
    sync_version: (item.sync_version || 0) + 1,
    is_loopback: item.is_loopback === true // پرچم ضد حلقه (Anti-Loop)
  }
}];

// الگوریتم پیشرفته حل تعارض (Conflict Resolution)
const incoming = $input.first().json;
const dbRecord = $input.first().json.postgresResult?.[0] || null;

// 1. مکانیزم ضد حلقه (Anti-Loop): اگر تغییر توسط خود سیستم sync ایجاد شده، نادیده بگیر
if (incoming.is_loopback) {
  return [{ json: { ...incoming, action: 'skip_loop', reason: 'Anti-loop triggered' } }];
}

// 2. اگر رکورد جدید است
if (!dbRecord) {
  return [{ json: { ...incoming, action: 'full_sync', reason: 'New record' } }];
}

// 3. اگر هش داده‌ها یکسان است، تغییری رخ نداده
if (dbRecord.data_hash === incoming.data_hash) {
  return [{ json: { ...incoming, action: 'skip_unchanged', reason: 'Data hash matches' } }];
}

// 4. تشخیص تعارض (Conflict Detection)
const dbTimestamp = new Date(dbRecord.last_updated).getTime();
const timeDiff = Math.abs(incoming.incoming_timestamp - dbTimestamp);

// اگر تفاوت زمانی کمتر از 5 ثانیه باشد، تعارض همزمانی (Race Condition) در نظر گرفته می‌شود
if (timeDiff < 5000) {
  // استراتژی حل تعارض: اولویت منبع (Source Priority: PostgreSQL > Airtable > MySQL)
  let winner = incoming.source_system;
  if (dbRecord.source_of_truth === 'postgresql') winner = 'postgresql';

  return [{ 
    json: { 
      ...incoming, 
      db_record: dbRecord,
      action: 'conflict_manual_review', 
      reason: `Race condition detected. Priority given to: ${winner}`,
      winner: winner
    } 
  }];
}

// 5. استراتژی پیش‌فرض: آخرین نوشتار برنده می‌شود (Last Write Wins)
if (incoming.incoming_timestamp > dbTimestamp) {
  return [{ json: { ...incoming, db_record: dbRecord, action: 'propagate_update', reason: 'Last Write Wins' } }];
} else {
  return [{ json: { ...incoming, db_record: dbRecord, action: 'skip_outdated', reason: 'Incoming data is older than DB' } }];
}

